import React from 'react'
import ReactApexChart from 'react-apexcharts'
import ApexCharts from 'apexcharts'
import './styles.css'

// No per-series colors, no foreColor, no grid.borderColor: the chart reads the
// --apx-* tokens from the cascade. theme.follow:'os' additionally tracks the
// operating system's light/dark setting with zero JS.
// Shared by the vanilla-js, React and Vue builds: the accent tokens the
// Shuffle button cycles through at runtime.
var ACCENTS = ['#e11d48', '#0e9d9a', '#d97706', '#7c3aed', '#4f46e5']

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [
      { name: 'Users', data: [3100, 4200, 3800, 5100, 4700, 6200, 5800] },
    ],
    options: {
      chart: {
        id: 'facetTokensChart',
        height: 400,
        type: 'area',
        fontFamily: 'sans-serif',
        animations: { enabled: true },
        toolbar: { show: false },
      },
      theme: {
        follow: 'os',
      },
      stroke: { curve: 'smooth', width: 2 },
      fill: {
        type: 'gradient',
        gradient: { opacityFrom: 0.35, opacityTo: 0.05 },
      },
      dataLabels: { enabled: false },
      title: {
        text: 'Weekly active users',
        align: 'left',
      },
      subtitle: {
        text: 'Colors come entirely from CSS --apx-* design tokens',
        align: 'left',
      },
      xaxis: {
        type: 'category',
        categories: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
      },
      grid: {
        borderColor: '#e0e0e0',
      },
    },
  })

  React.useEffect(() => {
    // The react-apexcharts wrapper owns the render, so reach the live instance by
    // its chart.id at event time. The buttons live in the html block, so they are
    // in the DOM when this effect runs. (ACCENTS lives in the shared head script.)
    const root = document.documentElement
    const stateEl = document.getElementById('state')
    let accentIdx = -1

    const currentMode = () =>
      root.classList.contains('apx-dark') ? 'dark' : 'light'
    const syncState = () => {
      stateEl.textContent = 'Current: ' + currentMode()
    }
    syncState()

    const onToggle = () => {
      root.classList.toggle('apx-dark')
      const chart = ApexCharts.getChartByID('facetTokensChart')
      if (chart) chart.updateOptions({ theme: { mode: currentMode() } })
      syncState()
    }
    const onShuffle = () => {
      accentIdx = (accentIdx + 1) % ACCENTS.length
      root.style.setProperty('--apx-accent', ACCENTS[accentIdx])
      const chart = ApexCharts.getChartByID('facetTokensChart')
      if (chart) chart.refreshTokens()
    }

    const toggleBtn = document.getElementById('toggle')
    const shuffleBtn = document.getElementById('shuffle')
    toggleBtn.addEventListener('click', onToggle)
    shuffleBtn.addEventListener('click', onShuffle)

    return () => {
      toggleBtn.removeEventListener('click', onToggle)
      shuffleBtn.removeEventListener('click', onShuffle)
    }
  }, [])

  return (
    <div>
      <div className="panel">
        <div className="controls">
          <button id="toggle">Toggle light / dark</button>
          <button id="shuffle">Shuffle accent token</button>
          <span id="state" className="state"></span>
        </div>
      </div>

      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="area"
          height={400}
        />
      </div>

      <div className="panel">
        <div className="note">
          Every color here comes from CSS <code>--apx-*</code> tokens (
          <code>--apx-accent</code>, <code>--apx-fore</code>,{' '}
          <code>--apx-grid</code>,<code>--apx-surface</code>) defined once in
          the stylesheet. The chart config sets no colors at all. The first
          button flips a class that swaps the token values; with{' '}
          <code>theme: &#123; follow: 'os' &#125;</code> the chart also tracks
          the OS <code>prefers-color-scheme</code> automatically, no JS
          required.
          <b>Shuffle accent token</b> changes only the CSS variable at runtime
          and calls <code>chart.refreshTokens()</code>, which re-reads the
          cascade and re-renders: the path for design-system theme switches that
          are not an OS color-scheme flip.
        </div>
      </div>
    </div>
  )
}

export default ApexChart

/* Facet (#13): define the chart's colors as CSS design tokens ONCE. Every
     ApexCharts instance on the page reads them, so the chart is part of your
     design system, not a separate color config. */
:root {
  --apx-accent: #4f46e5;
  --apx-fore: #1f2937;
  --apx-grid: #e5e7eb;
  --apx-surface: #ffffff;
  --page-bg: #ffffff;
  --page-fore: #1f2937;
}
/* The dark palette: the same tokens, different values. Toggling the theme
     needs no per-series color config in JS. */
:root.apx-dark {
  --apx-accent: #818cf8;
  --apx-fore: #e5e7eb;
  --apx-grid: #374151;
  --apx-surface: #0b0f19;
  --page-bg: #0b0f19;
  --page-fore: #e5e7eb;
}

body {
  background: var(--page-bg);
  color: var(--page-fore);
  transition:
    background 0.25s ease,
    color 0.25s ease;
}
#chart {
  max-width: 720px;
  margin: 16px auto;
}
.panel {
  max-width: 720px;
  margin: 16px auto;
  font-family: sans-serif;
}
.controls {
  display: flex;
  gap: 12px;
  align-items: center;
  margin-bottom: 8px;
}
.controls button {
  padding: 7px 16px;
  cursor: pointer;
  border: 1px solid var(--apx-grid);
  background: var(--apx-surface);
  color: var(--page-fore);
  border-radius: 6px;
  font-size: 14px;
}
.note {
  border-left: 3px solid var(--apx-accent);
  padding: 10px 14px;
  font-size: 13px;
  line-height: 1.55;
  background: color-mix(in srgb, var(--apx-accent) 8%, transparent);
  border-radius: 2px;
}
.note code {
  background: color-mix(in srgb, var(--apx-accent) 16%, transparent);
  padding: 1px 5px;
  border-radius: 3px;
}
.state {
  font-size: 13px;
}
